QUnit.test("Do not expand panels on validation that doesn't have an error Bug#8341", function (assert) {
  const survey = new SurveyModel({
    "elements": [
      {
        "type": "text",
        "name": "question1",
        "isRequired": true
      },
      {
        "type": "panel",
        "name": "panel1",
        "elements": [
          {
            "type": "text",
            "name": "question2"
          }
        ],
        "title": "Title",
        "state": "collapsed"
      },
      {
        "type": "panel",
        "name": "panel2",
        "elements": [
          {
            "type": "text",
            "name": "question3",
            "isRequired": true
          }
        ],
        "title": "Title",
        "state": "collapsed"
      },
      {
        "type": "panel",
        "name": "panel3",
        "elements": [
          {
            "type": "panel",
