            "elements": [
              {
                "type": "text",
                "name": "question4",
                "isRequired": true
              }
            ],
            "title": "Title",
            "state": "collapsed"
          }
        ],
        "title": "Title",
        "state": "collapsed"
      },
      {
        "type": "panel",
        "name": "panel5",
        "isRequired": true,
        "elements": [
          {
            "type": "text",
            "name": "question2"
          }
        ],
        "title": "Title",
        "state": "collapsed"
      },
